def workspace_actions_by_service() -> dict[str, list[str]]:
    out: dict[str, list[str]] = {}
    for item in GOOGLE_WORKSPACE_TOOL_CATALOG:
        out.setdefault(str(item["service_slug"]), []).append(str(item["action"]))
    return {k: sorted(set(v)) for k, v in out.items()}

def workspace_tool_action(tool: str) -> str:
    for item in GOOGLE_WORKSPACE_TOOL_CATALOG:
        if item["tool"] == tool:
            return str(item["action"])
    raise KeyError(tool)

def workspace_tool_service(tool: str) -> str:
    for item in GOOGLE_WORKSPACE_TOOL_CATALOG:
        if item["tool"] == tool:
            return str(item["service_slug"])
    raise KeyError(tool)

def workspace_catalog_tool_names() -> list[str]:
    return [str(item["tool"]) for item in GOOGLE_WORKSPACE_TOOL_CATALOG]
